data.content:
MSTest **does not have** `Assert.IsGreaterThan`, `Assert.IsInRange`, or similar comparison assertions. Those don't exist. Here's what MSTest actually provides for numeric checks:

| Need | MSTest Approach |
|---|---|
| Equality (float) | `Assert.AreEqual(expected, actual, delta)` |
| Comparison | `Assert.IsTrue(value > threshold)` |
| Range check | `Assert.IsTrue(value >= lo && value <= hi)` |
| Exceptions | `Assert.ThrowsException<T>(() => ...)` |

Here's a test class using the real MSTest API:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsExpected()
    {
        Assert.AreEqual(75.0, _calc.CalculatePercentage(3, 4), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundaries ──

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.999, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    // ── NormalizeScore ──

    [TestMethod]
    public void NormalizeScore_MidRange_ReturnsExpected()
    {
        double result = _calc.NormalizeScore(25, 50);
        Assert.AreEqual(50.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(120, 100);
        // No Assert.IsLessThanOrEqual — use Assert.IsTrue
        Assert.IsTrue(result <= 100.0, $"Expected ≤100 but got {result}");
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

**Key takeaways:**
- **`Assert.AreEqual(expected, actual, delta)`** — the `delta` overload is essential for `double` comparisons to avoid floating-point issues
- **`Assert.IsTrue(condition, message)`** — your only option for `>`, `<`, range checks; always add a message so failures are readable
- **`[DataTestMethod]` + `[DataRow]`** — ideal for testing grade boundaries systematically
- If you want richer assertions like `.Should().BeInRange()`, consider adding **FluentAssertions** (a third-party library)
